UPDATE order_tickets
SET
partner_order_code = #{reprCponIndictNo},
partner_order_number = #{reprCponSeq}
WHERE id = #{ticketId}

UPDATE order_tickets
SET
    ticket_used = true,
    ticket_used_date = #{usedDate}
WHERE partner_order_code = #{reprCponIndictNo}
  AND ticket_used = false
